patch:
diff --git a/llvm/lib/Transforms/Scalar/LICM.cpp b/llvm/lib/Transforms/Scalar/LICM.cpp
index fa04ced7182d..a38b29c41998 100644
--- a/llvm/lib/Transforms/Scalar/LICM.cpp
+++ b/llvm/lib/Transforms/Scalar/LICM.cpp
@@ -1465,14 +1465,20 @@ static Instruction *cloneInstructionInExitBlock(

   if (MSSAU.getMemorySSA()->getMemoryAccess(&I)) {
     // Create a new MemoryAccess and let MemorySSA set its defining access.
-    MemoryAccess *NewMemAcc = MSSAU.createMemoryAccessInBB(
-        New, nullptr, New->getParent(), MemorySSA::Beginning);
-    if (NewMemAcc) {
-      if (auto *MemDef = dyn_cast<MemoryDef>(NewMemAcc))
-        MSSAU.insertDef(MemDef, /*RenameUses=*/true);
-      else {
-        auto *MemUse = cast<MemoryUse>(NewMemAcc);
-        MSSAU.insertUse(MemUse, /*RenameUses=*/true);
+    // Only create a MemoryAccess if the cloned instruction actually accesses
+    // memory. The original instruction may have had a MemoryAccess but after
+    // transformations (e.g., unswitching) the cloned instruction might not
+    // access memory anymore.
+    if (New->mayReadFromMemory() || New->mayWriteToMemory()) {
+      MemoryAccess *NewMemAcc = MSSAU.createMemoryAccessInBB(
+          New, nullptr, New->getParent(), MemorySSA::Beginning);
+      if (NewMemAcc) {
+        if (auto *MemDef = dyn_cast<MemoryDef>(NewMemAcc))
+          MSSAU.insertDef(MemDef, /*RenameUses=*/true);
+        else {
+          auto *MemUse = cast<MemoryUse>(NewMemAcc);
+          MSSAU.insertUse(MemUse, /*RenameUses=*/true);
+        }
       }
     }
   }

